#include <stdio.h>

int memo[31];

int fibonacci(int n) {
    if (n <= 1) return n;
    if (memo[n] != -1) return memo[n];
    memo[n] = fibonacci(n - 1) + fibonacci(n - 2);
    return memo[n];
}

int main() {
    int T, n;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        if (scanf("%d", &n) != 1) return 0;
        for (int i = 0; i <= 30; ++i) memo[i] = -1;
        printf("%d", fibonacci(n));
        if (T) printf("\n");
    }
    return 0;
}

