import sys

memo = [-1] * 31

def fibonacci(n):
    if n <= 1:
        return n
    if memo[n] != -1:
        return memo[n]
    memo[n] = fibonacci(n - 1) + fibonacci(n - 2)
    return memo[n]

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    T = int(data[0])
    out = []
    idx = 1
    for _ in range(T):
        n = int(data[idx]); idx += 1
        for i in range(31):
            memo[i] = -1
        out.append(str(fibonacci(n)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

